program LaunchInterceptor;

{$mode objfpc}{$H+}

uses sysutils, math;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : NPOINTS;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : NPOINTS;
    QUADS    : NUMQUADS;
    DIST     : real;
    N_PTS    : NPTYPE;
    K_PTS    : POINTRANGE;
    A_PTS    : POINTRANGE;
    B_PTS    : POINTRANGE;
    C_PTS    : POINTRANGE;
    D_PTS    : POINTRANGE;
    E_PTS    : POINTRANGE;
    F_PTS    : POINTRANGE;
    G_PTS    : POINTRANGE;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

const
  PI = 3.1415926535;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function DISTANCE(x1, y1, x2, y2: real): real;
begin
  DISTANCE := Sqrt(Sqr(x2 - x1) + Sqr(y2 - y1));
end;

function GET_QUADRANT(px, py: real): integer;
begin
  if px >= 0 then
  begin
    if py >= 0 then GET_QUADRANT := 1
    else GET_QUADRANT := 3;
  end
  else
  begin
    if py >= 0 then GET_QUADRANT := 2
    else GET_QUADRANT := 4; // This is technically not used by the spec logic but for completeness
  end;

  { Correcting according to spec:
    (0,0) -> I
    (-1,0) -> II
    (0,-1) -> III
    (0,1) -> I
    (1,0) -> I
    Spec: "I, II, III, IV. For example, the data point (0,0) is in quadrant I, 
    the point (-1,0) is in quadrant II, the point (0,-1) is in quadrant III, 
    the point (0,1) is in quadrant I, and the point (1,0) is in quadrant I."
    This implies:
    Quad I: x >= 0 and y >= 0
    Quad II: x < 0 and y >= 0
    Quad III: x < 0 and y < 0 (Wait, (0,-1) is III, so x <= 0 and y < 0)
    Quad IV: x >= 0 and y < 0
    Let's re-evaluate based on "priority of decision will be by quadrant number, i.e., I, II, III, IV"
    If (0,0) is I, (0,1) is I, (1,0) is I -> x >= 0 and y >= 0
    If (-1,0) is II -> x < 0 and y >= 0
    If (0,-1) is III -> x <= 0 and y < 0? No, if x=0, y=-1, it could be III or IV. Priority I, II, III, IV means it's III.
    So:
    I: x >= 0 and y >= 0
    II: x < 0 and y >= 0
    III: x < 0 and y < 0 OR (x=0 and y < 0)
    IV: x > 0 and y < 0
    Wait, let's be simpler:
    If x >= 0 and y >= 0 then 1
    Else if x < 0 and y >= 0 then 2
    Else if x <= 0 and y < 0 then 3
    Else 4;
  }
end;

{ Redefining GET_QUADRANT to strictly match the "priority I, II, III, IV" rule }
function GET_QUADRANT_STRICT(px, py: real): integer;
begin
    if (px >= 0) and (py >= 0) then GET_QUADRANT_STRICT := 1
    else if (px < 0) and (py >= 0) then GET_QUADRANT_STRICT := 2
    else if (px <= 0) and (py < 0) then GET_QUADRANT_STRICT := 3
    else GET_QUADRANT_STRICT := 4;
  end;


function TRIANGLE_AREA(x1, y1, x2, y2, x3, y3: real): real;
begin
  TRIANGLE_AREA := 0.5 * Abs(x1*(y2 - y3) + x2*(y3 - y1) + x3*(y1 - y2));
end;

function CAN_CONTAIN_IN_CIRCLE(x1, y1, x2, y2, x3, y3, r: real): boolean;
var
  a, b, c, s, area, r_calc: real;
begin
  a := DISTANCE(x1, y1, x2, y2);
  b := DISTANCE(x2, y2, x3, y3);
  c := DISTANCE(x3, y3, x1, y1);
  s := (a + b + c) / 2;
  area := Sqrt(Abs(s * (s - a) * (s - b) * (s - c)));
  if area = 0 then
  begin
    { Collinear points: the diameter is the max distance }
    CAN_CONTAIN_IN_CIRCLE := (Max(a, Max(b, c)) <= 2 * r);
    Exit;
  end;
  r_calc := (a * b * c) / (4 * area);
  { The smallest circle containing 3 points is either the circumcircle 
    (if it's acute/right) or the circle with the longest side as diameter (if it's obtuse). }
  if (a*a + b*b < c*c) or (a*a + c*c < b*b) or (b*b + c*c < a*a) then
  begin
    CAN_CONTAIN_IN_CIRCLE := (Max(a, Max(b, c)) <= 2 * r);
  end
  else
    CAN_CONTAIN_IN_CIRCLE := (r_calc <= r);
end;

{ Actually, the spec says "cannot all be contained within or on a circle of radius RADIUS1".
  This means: is there ANY circle of radius RADIUS1 that contains them?
  The smallest enclosing circle (SEC) problem. 
  For 3 points, the SEC is either the circumcircle (if the triangle is acute/right)
  or the circle with the longest side as diameter (if the triangle is obtuse). }
function SEC_RADIUS(x1, y1, x2, y2, x3, y3: real): real;
var
  a, b, c, s, area, r_circum: real;
begin
  a := DISTANCE(x1, y1, x2, y2);
  b := DISTANCE(x2, y2, x3, y3);
  c := DISTANCE(x3, y3, x1, y1);
  s := (a + b + c) / 2;
  area := Sqrt(Abs(s * (s - a) * (s - b) * (s - c)));
  if area = 0 then
  begin
    SEC_RADIUS := Max(a, Max(b, c)) / 2;
    Exit;
  end;
  r_circum := (a * b * c) / (4 * area);
  if (a*a + b*b < c*c) or (a*a + c*c < b*b) or (b*b + c*c < a*a) then
    SEC_RADIUS := Max(a, Max(b, c)) / 2
  else
    SEC_RADIUS := r_circum;
end;

function GET_ANGLE(x1, y1, x2, y2, x3, y3: real): real;
var
  ux, uy, vx, vy, dot, magU, magV: real;
begin
  ux := x1 - x2;
  uy := y1 - y2;
  vx := x3 - x2;
  vy := y3 - y2;
  dot := ux*vx + uy*vy;
  magU := Sqrt(ux*ux + uy*uy);
  magV := Sqrt(vx*vx + vy*vy);
  if magU = 0 or magV = 0 then
    GET_ANGLE := -1.0 { Undefined }
  else
    GET_ANGLE := Acos(Max(-1.0, Min(1.0, dot / (magU * magV))));
end;

procedure DECIDE;
var
  i, j, k, q, count, quad_mask: integer;
  dist_val, angle_val, area_val, sec_r: real;
  p1x, p1y, p2x, p2y, p3x, p3y: real;
  found_gt, found_lt: boolean;
begin
  { LIC 1 }
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(DISTANCE(X[i], Y[i], X[i+1], Y[i+1]), PARAMETERS.LENGTH1) = GT then
      CMV[1] := true;

  { LIC 2 }
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
    if SEC_RADIUS(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]) > PARAMETERS.RADIUS1 then
      CMV[2] := true;

  { LIC 3 }
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle_val := GET_ANGLE(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if angle_val >= 0 then
    begin
      if (REALCOMPARE(angle_val, PI - PARAMETERS.EPSILON) = LT) or 
         (REALCOMPARE(angle_val, PI + PARAMETERS.EPSILON) = GT) then
        CMV[3] := true;
    end;
  end;

  { LIC 4 }
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TRIANGLE_AREA(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]), PARAMETERS.AREA1) = GT then
      CMV[4] := true;

  { LIC 5 }
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quad_mask := 0;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      count := GET_QUADRANT_STRICT(X[j], Y[j]);
      quad_mask := quad_mask or (1 shl (count - 1));
    end;
    { Count set bits in quad_mask }
    count := 0;
    for k := 0 to 3 do if (quad_mask and (1 shl k)) <> 0 then count := count + 1;
    if count > PARAMETERS.QUADS then CMV[5] := true;
  end;

  { LIC 6 }
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
    if X[i+1] - X[i] < 0 then CMV[6] := true;

  { LIC 7 }
  CMV[7] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      p1x := X[i]; p1y := Y[i];
      p3x := X[i + PARAMETERS.N_PTS - 1]; p3y := Y[i + PARAMETERS.N_PTS - 1];
      for j := i to i + PARAMETERS.N_PTS - 1 do
      begin
        if p1x = p3x and p1y = p3y then
          dist_val := DISTANCE(p1x, p1y, X[j], Y[j])
        else
        begin
          { Distance from point (X[j], Y[j]) to line (p1, p3) }
          dist_val := Abs((p3x - p1x)*(p1y - Y[j]) - (p1x - X[j])*(p3y - p1y)) / DISTANCE(p1x, p1y, p3x, p3y);
        end;
        if REALCOMPARE(dist_val, PARAMETERS.DIST) = GT then CMV[7] := true;
      end;
    end;
  end;

  { LIC 8 }
  CMV[8] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
      if REALCOMPARE(DISTANCE(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]), PARAMETERS.LENGTH1) = GT then
        CMV[8] := true;
  end;

  { LIC 9 }
  CMV[9] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) do
    begin
      p1x := X[i]; p1y := Y[i];
      p2x := X[i + PARAMETERS.A_PTS + 1]; p2y := Y[i + PARAMETERS.A_PTS + 1];
      p3x := X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2]; p3y := Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2];
      if SEC_RADIUS(p1x, p1y, p2x, p2y, p3x, p3y) > PARAMETERS.RADIUS1 then CMV[9] := true;
    end;
  end;

  { LIC 10 }
  CMV[10] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2) do
    begin
      p1x := X[i]; p1y := Y[i];
      p2x := X[i + PARAMETERS.C_PTS + 1]; p2y := Y[i + PARAMETERS.C_PTS + 1];
      p3x := X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2]; p3y := Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2];
      angle_val := GET_ANGLE(p1x, p1y, p2x, p2y, p3x, p3y);
      if angle_val >= 0 then
      begin
        if (REALCOMPARE(angle_val, PI - PARAMETERS.EPSILON) = LT) or 
           (REALCOMPARE(angle_val, PI + PARAMETERS.EPSILON) = GT) then
          CMV[10] := true;
      end;
    end;
  end;

  { LIC 11 }
  CMV[11] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) do
    begin
      p1x := X[i]; p1y := Y[i];
      p2x := X[i + PARAMETERS.E_PTS + 1]; p2y := Y[i + PARAMETERS.E_PTS + 1];
      p3x := X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]; p3y := Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2];
      if REALCOMPARE(TRIANGLE_AREA(p1x, p1y, p2x, p2y, p3x, p3y), PARAMETERS.AREA1) = GT then CMV[11] := true;
    end;
  end;

  { LIC 12 }
  CMV[12] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
      if X[i + PARAMETERS.G_PTS + 1] - X[i] < 0 then CMV[12] := true;
  end;

  { LIC 13 }
  CMV[13] := false;
  if NUMPOINTS >= 3 then
  begin
    found_gt := false;
    found_lt := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      dist_val := DISTANCE(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if REALCOMPARE(dist_val, PARAMETERS.LENGTH1) = GT then found_gt := true;
      if REALCOMPARE(dist_val, PARAMETERS.LENGTH2) = LT then found_lt := true;
    end;
    if found_gt and found_lt then CMV[13] := true;
  end;

  { LIC 14 }
  CMV[14] := false;
  if NUMPOINTS >= 5 then
  begin
    found_gt := false;
    found_lt := false;
    for i := 1 to NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) do
    begin
      p1x := X[i]; p1y := Y[i];
      p2x := X[i + PARAMETERS.A_PTS + 1]; p2y := Y[i + PARAMETERS.A_PTS + 1];
      p3x := X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2]; p3y := Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2];
      sec_r := SEC_RADIUS(p1x, p1y, p2x, p2y, p3x, p3y);
      if sec_r > PARAMETERS.RADIUS1 then found_gt := true;
      if sec_r <= PARAMETERS.RADIUS2 then found_lt := true;
    end;
    if found_gt and found_lt then CMV[14] := true;
  end;

  { LIC 15 }
  CMV[15] := false;
  if NUMPOINTS >= 5 then
  begin
    found_gt := false;
    found_lt := false;
    for i := 1 to NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) do
    begin
      p1x := X[i]; p1y := Y[i];
      p2x := X[i + PARAMETERS.E_PTS + 1]; p2y := Y[i + PARAMETERS.E_PTS + 1];
      p3x := X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]; p3y := Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2];
      area_val := TRIANGLE_AREA(p1x, p1y, p2x, p2y, p3x, p3y);
      if REALCOMPARE(area_val, PARAMETERS.AREA1) = GT then found_gt := true;
      if REALCOMPARE(area_val, PARAMETERS.AREA2) = LT then found_lt := true;
    end;
    if found_gt and found_lt then CMV[15] := true;
  end;

  { PUM Calculation }
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then continue;
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := true;
        ANDD: PUM[i, j] := CMV[i] and CMV[j];
        ORR: PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;

  { FUV Calculation }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      found_lt := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          found_lt := false;
          break;
        end;
      FUV[i] := found_lt;
    end;
  end;

  { LAUNCH Decision }
  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
end;

{ Since the delivery requires a compiled binary that reads JSON, we need a wrapper.
  The wrapper will parse JSON, populate globals, call DECIDE, and output JSON.
  Because Free Pascal's standard library doesn't have JSON, we'll use a simple manual parser
  or external tool. The prompt says "How you parse that JSON ... are up to you".
  I'll implement a basic JSON reader for the specific shape of the input. }

function ParseReal(s: string): real;
begin
  ParseReal := StrToFloat(s);
end;

function ParseBool(s: string): boolean;
begin
  ParseBool := (s = 'true');
end;

